hooks.command:
INFO=/tmp/shadowspeak-progress-info.txt; LOG="/Users/faithkayiwa/Documents/Faith Second Brain 2026/Progress Log.md"; [ -s "$INFO" ] || exit 0; TODAY=$(grep '^DATE:' "$INFO" | sed 's/^DATE: //'); COMMITS=$(awk '/^COMMITS:/{found=1;next} /^DIFF_STAT:/{found=0} found{print}' "$INFO"); DIFF=$(awk '/^DIFF_STAT:/{found=1;next} found{print}' "$INFO"); SUMMARY=$(echo "$COMMITS" | head -1 | sed 's/^[a-f0-9]* //'); BULLETS=$(echo "$COMMITS" | while IFS= read -r line; do MSG=$(echo "$line" | sed 's/^[a-f0-9]* //'); [ -n "$MSG" ] && echo "- ✅ $MSG"; done | head -6); ENTRY="
### ShadowSpeakLaunch — ${SUMMARY}

${BULLETS}
"; if grep -q "^## ${TODAY}" "$LOG"; then awk -v date="## ${TODAY}" -v entry="$ENTRY" 'found && /^## /{print entry; found=0} /^## /{if($0==date)found=1} {print}' "$LOG" > /tmp/ss-log-tmp.md && mv /tmp/ss-log-tmp.md "$LOG"; else printf "
## %s
%s" "$TODAY" "$ENTRY" >> "$LOG"; fi; rm -f "$INFO"
